//! Segment compaction for the tokenfold on-disk index layer (F-041 holdout slice).
use crate::index::segment::SegmentId;
use std::sync::atomic::Ordering;

/// Per-segment liveness stats sampled at the start of a compaction cycle.
pub struct SegmentStats {
    pub live_bytes: u64,
    pub tombstones: u32,
}

impl Compactor {
    /// True when a segment has accumulated enough tombstones to be rewritten.
    pub fn should_compact(&self, stats: &SegmentStats) -> bool {
        stats.tombstones > self.tombstone_threshold
    }

    /// Merge the chosen segments and hand back the id of the newly written one.
    pub fn merge_segments(&mut self, ids: &[SegmentId]) -> Result<SegmentId, CompactError> {
        let target = self.allocate_segment()?;
        self.write_merged(target, ids)?;
        Ok(target)
    }

    fn allocate_segment(&mut self) -> SegmentId {
        SegmentId(self.next_id.fetch_add(1, Ordering::SeqCst) + 1)
    }
}
